# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ management API credentials
rabbitmq_host = 'http://localhost:15672'
admin_username = 'admin'
admin_password = 'password'

# List of vhosts and corresponding users with permissions
vhosts_users_permissions = [
    {'vhost': '/app1', 'user': 'app1_user', 'password': 'app1_pass'},
    {'vhost': '/app2', 'user': 'app2_user', 'password': 'app2_pass'}
]

# Function to create a vhost
def create_vhost(vhost):
    url = f'{rabbitmq_host}/api/vhosts/{vhost}'
    headers = {'Content-Type': 'application/json'}
    data = {}
    response = requests.put(url, headers=headers, auth=(admin_username, admin_password), json=data)
    if response.status_code == 201:
        print(f'Vhost {vhost} created successfully.')
    else:
        print(f'Failed to create vhost {vhost}. Status code: {response.status_code}')

# Function to set user and permissions
def set_user_and_permissions(vhost, user, password):
    # Set user with password
    url = f'{rabbitmq_host}/api/users/{user}'
    headers = {'Content-Type': 'application/json'}
    data = {
        'password': password,
        'tags': ''
    }
    response = requests.put(url, headers=headers, auth=(admin_username, admin_password), json=data)
    if response.status_code == 204:
        print(f'User {user} created successfully.')
    else:
        print(f'Failed to create user {user}. Status code: {response.status_code}')
    
    # Set permissions for the vhost
    url = f'{rabbitmq_host}/api/permissions/{vhost}/{user}'
    headers = {'Content-Type': 'application/json'}
    data = {
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    }
    response = requests.put(url, headers=headers, auth=(admin_username, admin_password), json=data)
    if response.status_code == 204:
        print(f'Permissions for {user} in vhost {vhost} set successfully.')
    else:
        print(f'Failed to set permissions for {user} in vhost {vhost}. Status code: {response.status_code}')

# Main script
for item in vhosts_users_permissions:
    create_vhost(item['vhost'])
    set_user_and_permissions(item['vhost'], item['user'], item['password'])